def min_north_magnets(n, m, grid):
    # Step 1: Check if every row and column has at least one south magnet
    has_south_row = [False] * n
    has_south_col = [False] * m

    for i in range(n):
        for j in range(m):
            if grid[i][j] == '#':
                has_south_row[i] = True
                has_south_col[j] = True

    if not all(has_south_row) or not all(has_south_col):
        return -1

    # Step 2: Determine the minimum number of north magnets required
    north_magnets = 0

    for i in range(n):
        for j in range(m):
            if grid[i][j] == '#':
                # Ensure this black cell is reachable
                if not has_south_row[i]:
                    north_magnets += 1
                if not has_south_col[j]:
                    north_magnets += 1
            elif grid[i][j] == '.':
                # Ensure this white cell is not reachable
                if has_south_row[i] and has_south_col[j]:
                    north_magnets += 1

